// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Tab 部門成果 - Display data', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Tab 部門成果 - Display data', async function() {
    await driver.get("http://localhost:4200/user/list-evaluation");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-layout-content")).click();
    await driver.findElement(By.css(".ant-btn-primary > span")).click();
    await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(1)")).click();
    await driver.findElement(By.css(".ant-table-row-expand-icon")).click();
    assert(await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(1) > .ant-typography")).getText() == "test");
    assert(await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(2) > .ant-typography")).getText() == "test");
    assert(await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(3) > .ant-typography")).getText() == "test");
    assert(await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(4) > .ant-typography")).getText() == "100");
    assert(await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(5) > .ant-typography")).getText() == "1.2");
    assert(await driver.findElement(By.css("#rc-tabs-3-panel-1 .ant-table-summary:nth-child(4) .ant-table-cell:nth-child(2)")).getText() == "1.44");
  });
});
